import React from 'react';
import { DEMO_MODE } from '../config';  
const DemoBanner = () => {
  if (!DEMO_MODE) return null;
  
  return (
    <div style={{
      background: '#957bab',
      color: 'white',
      padding: '12px 20px',
      textAlign: 'center',
      fontWeight: 'bold',
      position: 'sticky',
      top: 0,
      zIndex: 9999,
      boxShadow: '0 2px 8px rgba(0,0,0,0.2)'
    }}>
      Changes can not be made in demo mode!
    </div>
  );
};

export default DemoBanner;
